const http = require("http");
const WebSocket = require("ws");
const crypto = require("crypto");

const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 8080;
const TICK_HZ = process.env.TICK_HZ ? parseInt(process.env.TICK_HZ, 10) : 10;
const TICK_MS = Math.max(10, Math.floor(1000 / Math.max(1, TICK_HZ)));

const MAP_W = process.env.MAP_W ? parseInt(process.env.MAP_W, 10) : 2000;
const MAP_H = process.env.MAP_H ? parseInt(process.env.MAP_H, 10) : 2000;

const MAX_PLAYERS = process.env.MAX_PLAYERS ? parseInt(process.env.MAX_PLAYERS, 10) : 64;
const MAX_MSG_BYTES = process.env.MAX_MSG_BYTES ? parseInt(process.env.MAX_MSG_BYTES, 10) : 64 * 1024;

