        (s.type === "hq" && unitType === "worker") ||
        (s.type === "barracks" && (unitType === "soldier" || unitType === "archer"));
      if (!allowed) return { ok: false, error: "not_allowed" };

      this.spend(player, cost);

      const angle = Math.random() * Math.PI * 2;
      const x = clamp(s.x + Math.cos(angle) * BUILD_RADIUS, 0, MAP_W);
      const y = clamp(s.y + Math.sin(angle) * BUILD_RADIUS, 0, MAP_H);
